import React from "react";

function AssignmentList({ assignments, submit }) {
  return (
    <div className="card">
      <h2>Assignments</h2>

      <ul>
        {/* Header Row */}
        <li className="assignment-header">
          <div>Title</div>
          <div>Subject</div>
          <div>Due Date</div>
          <div>Status</div>
          <div>Action</div>
        </li>

        {/* Empty State */}
        {assignments.length === 0 && (
          <li style={{ gridColumn: "1 / -1", textAlign: "center", padding: "15px" }}>
            No assignments available.
          </li>
        )}

        {/* Assignment Rows */}
        {assignments.map((a) => (
          <li key={a.id}>
            <div>{a.title}</div>
            <div>{a.subject}</div>
            <div>{a.dueDate}</div>

            <div>
              <span
                className={
                  a.status === "PENDING"
                    ? "status pending"
                    : "status submitted"
                }
              >
                {a.status}
              </span>
            </div>

            <div>
              {a.status === "PENDING" && (
                <button onClick={() => submit(a.id)}>
                  Submit
                </button>
              )}
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentList;
